// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 50
#define MAX_C 100
#define MAX_K 50

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, c, k;
        scanf("%d %d %d", &n, &c, &k);
        double expected_colors[MAX_N][MAX_C];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < c; j++) {
                expected_colors[i][j] = (j == 1) ? 1.0 : 0.0;
            }
        }
        for (int turn = 0; turn < k; turn++) {
            int Li, Ri;
            scanf("%d %d", &Li, &Ri);
            Li--; Ri--;
            double new_expected_colors[MAX_N][MAX_C];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < c; j++) {
                    new_expected_colors[i][j] = 0.0;
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < c; j++) {
                    if (i >= Li && i <= Ri) {
                        for (int new_color = 0; new_color < c; new_color++) {
                            new_expected_colors[i][(j * new_color) % c] += expected_colors[i][j] / c;
                        }
                    } else {
                        new_expected_colors[i][j] += expected_colors[i][j];
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < c; j++) {
                    expected_colors[i][j] = new_expected_colors[i][j];
                }
            }
        }
        double sum = 0.0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < c; j++) {
                sum += j * expected_colors[i][j];
            }
        }
        printf("%.6f\n", sum);
    }
    return 0;
}

