import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int c = scanner.nextInt();
            int k = scanner.nextInt();
            double[][] expectedColors = new double[n][c];
            for (int i = 0; i < n; i++) {
                expectedColors[i][1] = 1.0;
            }
            for (int turn = 0; turn < k; turn++) {
                int Li = scanner.nextInt() - 1;
                int Ri = scanner.nextInt() - 1;
                double[][] newExpectedColors = new double[n][c];
                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < c; j++) {
                        if (i >= Li && i <= Ri) {
                            for (int newColor = 0; newColor < c; newColor++) {
                                newExpectedColors[i][(j * newColor) % c] += expectedColors[i][j] / c;
                            }
                        } else {
                            newExpectedColors[i][j] += expectedColors[i][j];
                        }
                    }
                }
                expectedColors = newExpectedColors;
            }
            double sum = 0.0;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < c; j++) {
                    sum += j * expectedColors[i][j];
                }
            }
            System.out.printf("%.6f\n", sum);
        }
    }
}

